const input = $input.first().json;
const chatInput = input.chatInput || '';

// Basic sanitization (not covered by Guardrails)
function basicSanitize(text) {
  if (!text || typeof text !== 'string') return '';

  // 1. Limit maximum length (prevent context overflow)
  // 500 chars is generous for this chatbot: longest real message (full address + name) ~300 chars.
  // Prevents LLM token abuse and context overflow attacks.
  const maxLength = 500;
  let sanitized = text.substring(0, maxLength);

  // 2. Normalize Unicode (prevent homograph attacks)
  sanitized = sanitized.normalize('NFKC');

  // 3. Remove control characters (except newlines and tabs)
  sanitized = sanitized.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '');

  // 4. Remove zero-width characters (hidden characters)
  sanitized = sanitized.replace(/[\u200B-\u200D\uFEFF]/g, '');

  // 5. Trim whitespace
  sanitized = sanitized.trim();

  return sanitized;
}

const sanitized = basicSanitize(chatInput);

return [{ json: { ...input, chatInput: sanitized, originalInput: chatInput, basicSanitized: true } }];

