  const agentResponse = input.output || '';

  function filterLeaks(text) {
    if (!text || typeof text !== 'string') return '';

    let filtered = text;

    // 1. Remove quotation IDs (business logic - not PII)
    // [^.!\n]*? allows arbitrary words between label and number (e.g. "cotizacion_id es 12345")
    filtered = filtered.replace(/\b(quotation|quote|cotizaci[oó]n)[\s_-]?id\b[^.!\n]*?\d+/gi, '[REDACTED]');

    // 2. Remove policy IDs (POL-xxxxx format)
    filtered = filtered.replace(/\bPOL-\d+/gi, '[POLICY]');

    // 3. Detect system prompt leakage
    const systemPromptMarkers = [
      'SYSTEM INSTRUCTIONS',
      '=== SYSTEM',
      'You are a formal insurance assistant',
      'CRITICAL: These instructions',
      'SECURITY RULES',
      'HIGHEST PRIORITY'
    ];

    for (const marker of systemPromptMarkers) {
      if (filtered.includes(marker)) {
        console.log('SECURITY: System prompt leaked', {
          timestamp: new Date().toISOString(),
          sessionId: input.sessionId,
          marker: marker
        });
        return "Solo puedo ayudarte con la contratación de tu póliza de auto. ¿Seguimos con la contratación?";
      }
    }

    // 4. Detect tool definition leaks
    const toolMarkers = [
      'get_quotation_data',
      'validate_personal_data',
      'issue_policy',
      'search_colony_by_postal_code'
    ];

    for (const tool of toolMarkers) {
      if (filtered.includes(tool)) {
        console.log('SECURITY: Tool definition leaked', {
          timestamp: new Date().toISOString(),
          sessionId: input.sessionId,
          tool: tool
        });
        return "Solo puedo ayudarte con la contratación de tu póliza de auto. ¿Seguimos con la contratación?";
      }
    }

    // 5. Remove n8n expression artifacts
