// Read full context from Phase Extractor output
const ctx = $input.first().json;
const output = ctx.output || '';

// Detect [api_error:TOOL_NAME] marker
const apiErrorMatch = output.match(/\[api_error:([\w_]+)\]/);
const isApiError = !!apiErrorMatch;
const failedTool = apiErrorMatch ? apiErrorMatch[1] : null;

// Strip the marker so it never reaches Filter System Leaks or the user
const cleanOutput = output.replace(/\n?\[api_error:[\w_]+\]/g, '').trim();

return [{
  json: {
    ...ctx,
    output: cleanOutput,   // marker removed
    isApiError,            // true if API failed
    failedTool,            // 'get_quotation_data' | 'issue_policy' | null
  }
}];

const input = $input.first().json;

// Feature flag — set to false to disable all rate limiting instantly
const RATE_LIMITING_ENABLED = true;

if (!RATE_LIMITING_ENABLED) {
  return [{ json: { ...input, budgetExceeded: false, softWarning: false, budgetStatus: 'DISABLED' } }];
}

const phase = input.conversationPhase;
const rateLimitData = input.rateLimitData || {};
const phaseCounters = rateLimitData.phaseCounters || {};
const currentCount = phaseCounters[phase] ?? 0;

const PHASE_LIMITS = {
  greeting:              { hard: 10, soft: 8 },
  data_capture:          { hard: 25, soft: 20 },
  summary_confirmation:  { hard: 8,  soft: 6  },
  policy_issuance:       { hard: 5,  soft: 4  },
  payment_pending:       { hard: 10, soft: 7 },
};

const limits = PHASE_LIMITS[phase];

// Unknown or completed phase — pass through
if (!limits) {
  return [{ json: { ...input, budgetExceeded: false, softWarning: false, budgetStatus: 'OK' } }];
}

if (currentCount >= limits.hard) {
  console.log('Message Budget Guard: EXCEEDED', {
    sessionId: input.sessionId,
    phase,
    currentCount,
    hardLimit: limits.hard
  });

  const humanAgentUrl = `https://api.whatsapp.com/send?phone=525634352430&text=Quiero%20continuar%20con%20mi%20cotizacion%20${input.quotationId}`;

  return [{
    json: {
      budgetExceeded: true,
      output: `Hemos alcanzado el límite de mensajes para esta etapa de su proceso.\nPara continuar con su contratación, le invitamos a hablar con uno de nuestros agentes especializados:\n${humanAgentUrl}\nNuestro horario de atención es de 8am - 5pm, Lunes a Viernes.`,
      blocked: true,
      reason: 'budget_exceeded',
      sessionId: input.sessionId,
      phoneNumber: input.phoneNumber
    }
  }];
}

const softWarning = currentCount >= limits.soft;

return [{
  json: {
    ...input,
    budgetExceeded: false,
    budgetStatus: softWarning ? 'SOFT_WARNING' : 'OK',
    softWarning: softWarning
  }
}];

const input = $input.first().json;

 // Feature flag — must match the constant in Message Budget Guard
