console.log('dataToValidate:', JSON.stringify(dataToValidate, null, 2));

// Validation function
function validatePersonalData(data) {
  const errors = {};
  let hasErrors = false;

  // Email validation
  if (data.email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(data.email)) {
      errors.email = "Formato inválido. Ejemplo: usuario@ejemplo.com";
      hasErrors = true;
    }
  }

  // Phone validation (10 digits)
  if (data.telefono) {
    const phoneRegex = /^\d{10}$/;
    if (!phoneRegex.test(data.telefono)) {
      errors.telefono = "Debe tener exactamente 10 dígitos. Ejemplo: 5563125678";
      hasErrors = true;
    }
  }

  if (data.numero_identificacion) {
    const ineRegex = /^\d{10}$/;
    if (!ineRegex.test(data.numero_identificacion)) {
      errors.numero_identificacion = "Debe tener exactamente 10 dígitos. Ejemplo: 1152444889";
      hasErrors = true;
    }
  }

  // Date of birth validation (DD/MM/AAAA) and age >= 18
  if (data.fecha_nacimiento) {
    const dateRegex = /^(\d{2})\/(\d{2})\/(\d{4})$/;
    const match = data.fecha_nacimiento.match(dateRegex);

    if (!match) {
      errors.fecha_nacimiento = "Formato inválido. Ejemplo: 03/12/1992 (DD/MM/AAAA)";
      hasErrors = true;
    } else {
      const [_, day, month, year] = match;
      const birthDate = new Date(year, month - 1, day);
      const today = new Date();
      let age = today.getFullYear() - birthDate.getFullYear();
      const monthDiff = today.getMonth() - birthDate.getMonth();

      if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
        age--;
      }

      if (age < 18) {
        errors.fecha_nacimiento = "Debe ser mayor de 18 años";
        hasErrors = true;
      }
    }
  }

  // RFC validation (4 letters + 6 digits + 3 alphanumeric)
  if (data.rfc) {
    const rfcRegex = /^[A-ZÑ&]{4}\d{6}([A-Z0-9]{3})?$/;
    if (!rfcRegex.test(data.rfc.toUpperCase())) {
      errors.rfc = "Formato inválido. Debe ser 10 chars (PEGJ900515) o 13 chars (PEGJ900515ABC)";
      hasErrors = true;
    }
  }

  // Placas validation (7 alphanumeric characters)
  if (data.placas) {
    const placasRegex = /^[A-Z0-9]{6,7}$/;
    if (!placasRegex.test(data.placas.toUpperCase())) {
      errors.placas = "Formato inválido. Debe ser 6 o 7 caracteres alfanuméricos (ej. ABC123 o ABC1234)";
      hasErrors = true;
    }
  }

  if (data.serie) {
    const serieNorm = String(data.serie).trim().toUpperCase();
    const vinRegex = /^[A-HJ-NPR-Z0-9]{8}[0-9X][A-HJ-NPR-Z0-9]{8}$/;
    if (!vinRegex.test(serieNorm)) {
      errors.serie = "El número de serie (NIV/VIN) debe tener exactamente 17 caracteres, sin espacios ni guiones y sin las letras I, O ni Q (el 9º carácter es un dígito o X). Ejemplo: 3VWFE21C04M000001";
      hasErrors = true;
    }
  }

  // Postal code validation (5 digits)
  if (data.codigo_postal) {
    const cpRegex = /^\d{5}$/;
    if (!cpRegex.test(data.codigo_postal)) {
      errors.codigo_postal = "Debe tener exactamente 5 dígitos. Ejemplo: 01460";
      hasErrors = true;
    }
  }

  // Gender validation (optional - M or F)
  if (data.genero) {
    const validGenders = ['M', 'F'];
    if (!validGenders.includes(data.genero.toUpperCase())) {
      errors.genero = "Debe ser M (masculino) o F (femenino)";
      hasErrors = true;
    }
  }

  return {
    valid: !hasErrors,
    errors: errors
  };
}

// Execute validation
const result = validatePersonalData(dataToValidate);

// CRITICAL: Code Tools must return STRING, not objects
// AI Agents expect human-readable text responses they can interpret
if (!result.valid) {
  // Format errors as readable text for the AI Agent
  let errorMessage = "Validation failed with the following errors:\n";

  for (const [field, message] of Object.entries(result.errors)) {
    errorMessage += `- ${field}: ${message}\n`;
  }

  return errorMessage;
} else {
  return "Validation successful: All personal data fields are correctly formatted.";
}

